const raw = $input.first().json;
const body = raw.body || raw;

const firstName = (body.firstName || body.first_name || '').trim();
const lastName = (body.lastName || body.last_name || '').trim();
const email = (body.email || '').trim().toLowerCase();
const phone = (body.phone || '').trim();

// Diagnostic answers
const q1_situation = body.q1_situation || ''; // primary challenge
const q2_timeline = body.q2_timeline || ''; // how long in current situation
const q3_tried = body.q3_tried || ''; // what they've tried
const q4_goal = body.q4_goal || ''; // what success looks like in 90 days
const q5_commitment = body.q5_commitment || ''; // readiness level 1-5
const q6_pathway = body.q6_pathway || ''; // which resonates: Rise, Launch, or Academy

// Validation
if (!firstName || !email) {
  return [{ json: { valid: false, error: 'Name and email are required.' } }];
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  return [{ json: { valid: false, error: 'Please provide a valid email address.' } }];
}

// Pathway scoring logic
let recommendedPathway = 'Rise & Reclaim';
let pathwayTag = 'pathway-rise';
let pathwayUrl = 'https://beaconmomentum.com/rise';
let pathwayMessage = 'Your answers point to a foundation-first approach. The Rise & Reclaim pathway is designed for exactly where you are — building clarity, stability, and momentum before anything else.';

if (q6_pathway === 'Launch' || q1_situation.toLowerCase().includes('business') || q1_situation.toLowerCase().includes('income') || q1_situation.toLowerCase().includes('solopreneur')) {
  recommendedPathway = 'Solopreneur Launchpad';
  pathwayTag = 'pathway-launch';
  pathwayUrl = 'https://beaconmomentum.com/launch';
  pathwayMessage = 'Your answers show you are ready to build. The Solopreneur Launchpad pathway gives you the tools, community, and accountability to launch and grow your own income stream — on your terms.';
} else if (q6_pathway === 'Academy' || q1_situation.toLowerCase().includes('financial') || q1_situation.toLowerCase().includes('wealth') || q1_situation.toLowerCase().includes('invest')) {
  recommendedPathway = 'Beacon Academy';
  pathwayTag = 'pathway-academy';
  pathwayUrl = 'https://beaconmomentum.com/academy';
  pathwayMessage = 'Your answers show a readiness to build long-term wealth. The Beacon Academy pathway covers ethical wealth building, financial literacy, and the tools to create lasting financial independence.';
}

// Commitment scoring
const commitmentScore = parseInt(q5_commitment) || 3;
let urgencyTag = 'commitment-medium';
if (commitmentScore >= 4) urgencyTag = 'commitment-high';
if (commitmentScore <= 2) urgencyTag = 'commitment-low';

const timestamp = new Date().toLocaleString('en-US', {
  timeZone: 'America/New_York',
  dateStyle: 'medium',
  timeStyle: 'short'
});

return [{
  json: {
    valid: true,
    firstName,
    lastName,
    fullName: `${firstName} ${lastName}`.trim(),
    email,
    phone,
    q1_situation,
    q2_timeline,
    q3_tried,
    q4_goal,
    q5_commitment: commitmentScore,
    q6_pathway,
    recommendedPathway,
    pathwayTag,
    pathwayUrl,
    pathwayMessage,
    urgencyTag,
    timestamp
  }
}];

const d = $('Parse & Validate Submission').item.json;

const subject = `${d.firstName}, here is your Next Right Step`;

const htmlBody = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><style>
  body { font-family: Georgia, serif; background: #0d1117; color: #e8e0d0; margin: 0; padding: 0; }
  .container { max-width: 600px; margin: 0 auto; padding: 40px 20px; }
  .header { border-bottom: 2px solid #c9a84c; padding-bottom: 20px; margin-bottom: 30px; }
  .logo { font-size: 22px; font-weight: bold; color: #c9a84c; letter-spacing: 2px; }
  .tagline { font-size: 12px; color: #8a9bb0; margin-top: 4px; }
  h1 { color: #c9a84c; font-size: 24px; margin-bottom: 8px; }
  .pathway-box { background: #1a2332; border-left: 4px solid #c9a84c; padding: 20px; margin: 24px 0; border-radius: 4px; }
  .pathway-name { font-size: 20px; font-weight: bold; color: #c9a84c; margin-bottom: 8px; }
  .pathway-desc { font-size: 15px; line-height: 1.7; color: #c8d8e8; }
  .cta-button { display: inline-block; background: #c9a84c; color: #0d1117; padding: 14px 32px; border-radius: 4px; text-decoration: none; font-weight: bold; font-size: 16px; margin: 24px 0; }
  .footer { border-top: 1px solid #2a3a4a; padding-top: 20px; margin-top: 40px; font-size: 12px; color: #5a6a7a; }
  .watch { font-style: italic; color: #c9a84c; font-size: 14px; margin-top: 16px; }
</style></head>
<body>
<div class="container">
  <div class="header">
    <div class="logo">BEACON MOMENTUM</div>
    <div class="tagline">The Lighthouse is Lit</div>
  </div>

  <h1>${d.firstName}, your Next Right Step is clear.</h1>

  <p>Thank you for taking the time to complete the audit. What you shared matters, and it tells a clear story about where you are and where you are headed.</p>

  <div class="pathway-box">
    <div class="pathway-name">Your Recommended Pathway: ${d.recommendedPathway}</div>
    <div class="pathway-desc">${d.pathwayMessage}</div>
  </div>

  <p>The $297 Beacon Momentum membership gives you full access to the ${d.recommendedPathway} pathway — including the community, the curriculum, the tools, and the accountability structure that makes the difference between knowing what to do and actually doing it.</p>

  <p>There is no pressure here. But if you are ready to take the next right step, the door is open.</p>

  <a href="${d.pathwayUrl}" class="cta-button">Begin the ${d.recommendedPathway} Pathway</a>

  <p style="font-size: 14px; color: #8a9bb0;">If you have questions before joining, simply reply to this email. A real person reads every response.</p>

  <div class="watch">The lighthouse is lit. The Watch continues. — Beacon Momentum</div>

  <div class="footer">
    <p>You received this because you completed the Next Right Step Audit at beaconmomentum.com.</p>
    <p>Beacon Momentum, LLC | Wyoming, USA | <a href="https://beaconmomentum.com/unsubscribe" style="color: #5a6a7a;">Unsubscribe</a></p>
  </div>
</div>
</body>
</html>
`;

return [{ json: { subject, htmlBody, toEmail: d.email, toName: d.fullName } }];

